// --- CONFIGURACION PARA PRUEBAS ---
// Si estos valores no son null, sobrescribiran lo que venga de los flujos anteriores.
// Ideal para forzar pruebas rapidas sin pelear con n8n.
// Para volver a produccion (procesar todo), dejalos en null.
const FORZAR_BATCH_INDEX = 1; // Cambiar a null para produccion
const FORZAR_BATCH_SIZE = 3;  // Cambiar a null para produccion
const FORZAR_MODELO = null;   // Ej: 'qwen2.5:3b' (si es null usa el que venga por defecto)
// ----------------------------------

const rows = $input.all().map((item) => item.json || {});
const sourceRow = rows.find((row) => row && row.rawRelease) || rows.find((row) => row && row.fullEvidence) || rows.find((row) => row && row.prompt) || rows[0] || {};
const rawRelease = sourceRow.rawRelease || null;
const fullEvidence = sourceRow.fullEvidence || null;
const release = (rawRelease && rawRelease.release) || (fullEvidence && fullEvidence.release) || sourceRow.release || {};
const legacyPrompt = (!rawRelease && !fullEvidence)
  ? (String(sourceRow.prompt || sourceRow.aiPrompt || sourceRow.readmePrompt || '').trim() || null)
  : null;
const requestedBatchSize = FORZAR_BATCH_SIZE !== null ? FORZAR_BATCH_SIZE : Number(sourceRow.batchCommitSize || sourceRow.batchSize || 5);
const batchCommitSize = Math.max(1, Math.min(Number.isFinite(requestedBatchSize) ? requestedBatchSize : 5, 20));
const rawBatchIndex = FORZAR_BATCH_INDEX !== null ? String(FORZAR_BATCH_INDEX) : String(sourceRow.batchIndex ?? sourceRow.batch ?? '').trim();
const batchIndex = rawBatchIndex ? Math.max(1, Number(rawBatchIndex)) : null;
const localAiBaseUrl = String(sourceRow.localAiBaseUrl || 'http://localhost:11434').trim() || 'http://localhost:11434';
const localAiModel = FORZAR_MODELO !== null ? FORZAR_MODELO : (String(sourceRow.localAiModel || 'qwen2.5:3b').trim() || 'qwen2.5:3b');
const requestedBudget = Number(sourceRow.maxAiPayloadChars || sourceRow.aiPayloadMeta?.maxAiPayloadChars || 12000);
const maxAiPayloadChars = Math.max(4000, Math.min(Number.isFinite(requestedBudget) ? requestedBudget : 12000, 24000));

if (rawBatchIndex && (!Number.isFinite(batchIndex) || batchIndex < 1)) {
  throw new Error('batchIndex debe ser un entero positivo o vacio para procesar todos los lotes.');
}

if (!rawRelease && !fullEvidence && !legacyPrompt) {
  throw new Error('Missing release evidence. Expected rawRelease, fullEvidence or prompt from workflow 04.');
}

return [{
  json: {
    kind: 'technicalBatchPipelineInput',
    release: release,
    rawRelease: rawRelease,
    fullEvidence: fullEvidence,
    legacyPrompt: legacyPrompt,
    batchCommitSize: batchCommitSize,
    batchIndex: batchIndex,
    localAiBaseUrl: localAiBaseUrl,
    localAiModel: localAiModel,
    maxAiPayloadChars: maxAiPayloadChars
  }
}];

const input = $input.first().json || {};
const rawRelease = input.rawRelease || {};
const fullEvidence = input.fullEvidence || {};

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(values) {
  return [...new Set(asArray(values).filter(Boolean))];
}

function normalizeActor(value) {
  if (!value) return null;
  if (typeof value === 'string') return value.trim() || null;
  if (typeof value !== 'object') return String(value).trim() || null;
  return String(
    value.displayName ||
    value.name ||
    value.login ||
    value.username ||
    value.emailAddress ||
    value.email ||
    value.id ||
    ''
  ).trim() || null;
}

function isVisibleFile(file) {
  const filename = String((file && file.filename) || '').trim();
  if (!filename) return false;
  const baseName = filename.split(/[\/\\]/).pop() || filename;
  return !/^image-\d{8}-\d{6}\.(png|jpg|jpeg|gif|webp)$/i.test(baseName);
}

function cleanCommitMessage(message) {
  let text = String(message || '');
  text = text.replace(/\/\*+/g, ' ');
  text = text.replace(/\*+\//g, ' ');
  text = text.replace(/(^|\s)\/+(?=\S)/g, ' ');
  text = text.replace(/(?<=\S)\/+(?=\s|$)/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function compactText(value, max) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (!text) return null;
  if (text.length > max) return text.slice(0, max - 3).trimEnd() + '...';
  return text;
}

function formatDateTime(value) {
  if (!value) return null;
  const text = String(value).trim();
  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(text)) return text;
  const date = new Date(text);
  if (Number.isNaN(date.getTime())) return text;
  return date.toISOString().replace('T', ' ').slice(0, 19);
}

function formatStats(stats, filesCount) {
  if (!stats || typeof stats !== 'object') {
    return filesCount ? filesCount + ' archivos' : null;
  }
  const additions = stats.additions !== undefined ? stats.additions : (stats.added !== undefined ? stats.added : null);
  const deletions = stats.deletions !== undefined ? stats.deletions : (stats.removed !== undefined ? stats.removed : null);
  const changes = stats.total !== undefined ? stats.total : (stats.changes !== undefined ? stats.changes : null);
  const parts = [];
  if (additions !== null) parts.push('+' + additions);
  if (deletions !== null) parts.push('-' + deletions);
  if (changes !== null) parts.push(changes + ' cambios');
  if (filesCount) parts.push(filesCount + ' archivos');
  return parts.length ? parts.join(' | ') : null;
}

function sanitizeCommit(commit) {
  const clone = Object.assign({}, commit || {});
  clone.message = cleanCommitMessage(clone.message);
  clone.author = normalizeActor(clone.author);
  clone.files = asArray(clone.files).filter(isVisibleFile);
  clone.originSisKeys = asArray(clone.originSisKeys);
  clone.isMergeCommit = Boolean(clone.isMergeCommit) || /^merge\b/i.test(clone.message);
  return clone;
}

function sanitizeIssue(issue) {
  const clone = Object.assign({}, issue || {});
  clone.comments = asArray(clone.comments).slice(0, 2).map((comment) => ({
    ...comment,
    author: normalizeActor(comment && comment.author)
  }));
  clone.assignee = normalizeActor(clone.assignee);
  clone.labels = asArray(clone.labels);
  clone.components = asArray(clone.components);
  clone.fixVersions = asArray(clone.fixVersions);
  clone.originCommitShas = asArray(clone.originCommitShas);
  clone.relationships = clone.relationships || {};
  clone.fetchErrors = asArray(clone.fetchErrors);
  return clone;
}

function renderRecList(recKeys, recMap) {
  if (!recKeys.length) return '';
  const lines = ['#### REC relacionados'];
  for (const recKey of recKeys) {
    const rec = recMap.get(recKey);
    const summary = compactText(rec && rec.summary, 140);
    lines.push(summary ? '- ' + recKey + ' - ' + summary : '- ' + recKey);
  }
  return lines.join('\n');
}

function renderJiraSection(issueLike) {
  const lines = ['#### Jira'];
  if (issueLike.status) lines.push('- Estado: ' + issueLike.status);
  if (issueLike.issueType) lines.push('- Tipo: ' + issueLike.issueType);
  if (issueLike.priority) lines.push('- Prioridad: ' + issueLike.priority);
  if (issueLike.assignee) lines.push('- Responsable: ' + issueLike.assignee);
  if (issueLike.labels.length) lines.push('- Etiquetas: ' + issueLike.labels.join(', '));
  if (issueLike.components.length) lines.push('- Componentes: ' + issueLike.components.join(', '));
  if (issueLike.fixVersions.length) lines.push('- FixVersions: ' + issueLike.fixVersions.join(', '));
  if (issueLike.relatedSis.length) lines.push('- SIS relacionados: ' + issueLike.relatedSis.join(', '));
  if (issueLike.recKeys.length) lines.push('- REC: ' + issueLike.recKeys.join(', '));
  if (issueLike.description) lines.push('- Descripcion: ' + issueLike.description);
  return lines.join('\n');
}

function renderCommentsSection(comments) {
  const validComments = asArray(comments).filter((comment) => comment && comment.body);
  if (!validComments.length) return '';
  const lines = ['#### Resumen de comentarios Jira'];
  for (const comment of validComments) {
    const meta = [formatDateTime(comment.created), comment.author].filter(Boolean).join(' - ');
    const summary = compactText(comment.body, 320);
    lines.push(meta ? '- ' + meta + ': ' + summary : '- ' + summary);
  }
  return lines.join('\n');
}

function renderFilesSection(files) {
  const validFiles = asArray(files).filter((file) => file && file.filename);
  if (!validFiles.length) return '';
  const lines = ['##### Archivos modificados'];
  for (const file of validFiles) {
    const metrics = [
      file.status || 'modified',
      file.additions !== undefined ? '+' + file.additions : null,
      file.deletions !== undefined ? '-' + file.deletions : null,
      file.changes !== undefined ? file.changes + ' cambios' : null
    ].filter(Boolean).join(' | ');
    lines.push('- ' + file.filename + (metrics ? ' - ' + metrics : ''));
  }
  return lines.join('\n');
}

function renderCommitSection(commit) {
  const shortSha = commit.sha ? String(commit.sha).slice(0, 10) : 'sin-sha';
  const meta = [formatDateTime(commit.date), commit.author].filter(Boolean).join(' - ');
  const lines = ['- ' + shortSha + (meta ? ' - ' + meta : '')];
  lines.push('  Mensaje: ' + cleanCommitMessage(commit.message));
  const stats = commit.statsText || formatStats(commit.stats, commit.files.length);
  if (stats) lines.push('  Stats: ' + stats);
  const filesSection = renderFilesSection(commit.files);
  if (filesSection) lines.push(filesSection);
  return lines.join('\n');
}

function buildCompactIssue(issue, linkedCommits, recMap) {
  const recKeys = unique(asArray(issue.relationships ? issue.relationships.recKeys : []));
  return {
    k: issue.key,
    t: issue.summary || issue.key,
    st: issue.status || null,
    tp: issue.issueType || null,
    p: issue.priority || null,
    a: issue.assignee || null,
    l: issue.labels,
    cp: issue.components,
    fv: issue.fixVersions,
    rs: unique(asArray(issue.relationships ? issue.relationships.relatedSisKeys : [])),
    rr: recKeys,
    d: compactText(issue.description, 1600),
    cm: asArray(issue.comments)
      .filter((comment) => comment && comment.body)
      .map((comment) => ({
        dt: formatDateTime(comment.created),
        au: normalizeActor(comment.author),
        b: compactText(comment.body, 320)
      })),
    c: linkedCommits.map((commit) => ({
      sh: commit.sha || null,
      dt: formatDateTime(commit.date),
      au: normalizeActor(commit.author),
      m: cleanCommitMessage(commit.message),
      sg: formatStats(commit.stats, commit.files.length),
      f: asArray(commit.files).filter((file) => file && file.filename).map((file) => ({
        p: file.filename,
        s: file.status || 'modified',
        a: file.additions !== undefined ? file.additions : null,
        d: file.deletions !== undefined ? file.deletions : null,
        c: file.changes !== undefined ? file.changes : null
      }))
    })),
    recMap: recMap
  };
}

function buildSegmentPayload(issuePayload, commitsSlice, includeDetails, partIndex, partCount, releaseVersion) {
  return {
    r: releaseVersion,
    k: issuePayload.k,
    pt: partIndex,
    pc: partCount,
    s: {
      k: issuePayload.k,
      t: issuePayload.t,
      st: includeDetails ? issuePayload.st : null,
      tp: includeDetails ? issuePayload.tp : null,
      p: includeDetails ? issuePayload.p : null,
      a: includeDetails ? issuePayload.a : null,
      l: includeDetails ? issuePayload.l : [],
      cp: includeDetails ? issuePayload.cp : [],
      fv: includeDetails ? issuePayload.fv : [],
      rs: includeDetails ? issuePayload.rs : [],
      rr: includeDetails ? issuePayload.rr : [],
      d: includeDetails ? issuePayload.d : null,
      cm: includeDetails ? issuePayload.cm : [],
      c: commitsSlice.map((commit) => ({
        sh: commit.sh,
        dt: commit.dt,
        au: commit.au,
        m: commit.m,
        sg: commit.sg,
        f: commit.f
      }))
    }
  };
}

function splitLargeCommit(commit, buildPayload, budget) {
  const files = asArray(commit.f);
  if (!files.length) {
    return [{
      sh: commit.sh,
      dt: commit.dt,
      au: commit.au,
      m: compactText(commit.m, 400),
      sg: commit.sg,
      f: []
    }];
  }

  const fragments = [];
  let current = [];

  for (const file of files) {
    const candidate = current.concat([file]);
    const candidateCommit = { ...commit, f: candidate };
    if (current.length && JSON.stringify(buildPayload([candidateCommit])).length > budget) {
      fragments.push({ ...commit, f: current.slice() });
      current = [file];
      continue;
    }
    current = candidate;
  }

  if (current.length) {
    fragments.push({ ...commit, f: current.slice() });
  }

  return fragments;
}

function splitIssueByBudget(issuePayload, budget, releaseVersion, maxCommitsPerSegment) {
  const commits = asArray(issuePayload.c);
  if (!commits.length) {
    return [buildSegmentPayload(issuePayload, [], true, 1, 1, releaseVersion)];
  }

  const segments = [];
  let current = [];
  let currentPart = 1;

  const measure = (commitsSlice, includeDetails) => JSON.stringify(buildSegmentPayload(issuePayload, commitsSlice, includeDetails, currentPart, 999, releaseVersion)).length;

  for (const commit of commits) {
    const includeDetails = segments.length === 0;
    const singleSize = measure([commit], includeDetails);
    if (singleSize > budget) {
      const fragments = splitLargeCommit(commit, (slice) => buildSegmentPayload(issuePayload, slice, includeDetails && current.length === 0, currentPart, 999, releaseVersion), budget);
      for (const fragment of fragments) {
        const candidate = current.concat([fragment]);
        if (current.length && (measure(candidate, includeDetails) > budget || candidate.length > maxCommitsPerSegment)) {
          segments.push({ commits: current.slice(), includeDetails });
          current = [fragment];
          currentPart += 1;
        } else {
          current = candidate;
        }
      }
      continue;
    }

    const candidate = current.concat([commit]);
    if (current.length && (measure(candidate, includeDetails) > budget || candidate.length > maxCommitsPerSegment)) {
      segments.push({ commits: current.slice(), includeDetails });
      current = [commit];
      currentPart += 1;
      continue;
    }

    current = candidate;
  }

  if (current.length || !segments.length) {
    segments.push({ commits: current.slice(), includeDetails: segments.length === 0 });
  }

  return segments.map((segment, index) => buildSegmentPayload(issuePayload, segment.commits, segment.includeDetails, index + 1, segments.length, releaseVersion));
}

function renderSegmentMarkdown(payload, recMap) {
  const issueLike = {
    status: payload.s.st,
    issueType: payload.s.tp,
    priority: payload.s.p,
    assignee: payload.s.a,
    labels: asArray(payload.s.l),
    components: asArray(payload.s.cp),
    fixVersions: asArray(payload.s.fv),
    relatedSis: asArray(payload.s.rs),
    recKeys: asArray(payload.s.rr),
    description: payload.s.d
  };
  const segmentCommits = asArray(payload.s.c).map((commit) => ({
    sha: commit.sh,
    date: commit.dt,
    author: commit.au,
    message: commit.m,
    stats: null,
    statsText: commit.sg || null,
    files: asArray(payload.s.c).length > 0 ? asArray(commit.f).map((file) => ({
      filename: file.p,
      status: file.s,
      additions: file.a,
      deletions: file.d,
      changes: file.c
    })) : []
  }));
  const commentSection = renderCommentsSection(asArray(payload.s.cm).map((comment) => ({ created: comment.dt, author: comment.au, body: comment.b })));
  const recSection = renderRecList(asArray(payload.s.rr), recMap);
  const titleSuffix = payload.pc > 1 ? ' (parte ' + payload.pt + '/' + payload.pc + ')' : '';
  const sections = [
    '### ' + payload.s.k + ' - ' + payload.s.t + titleSuffix,
    renderJiraSection(issueLike),
    recSection,
    '#### Commits asociados',
    segmentCommits.length ? segmentCommits.map(renderCommitSection).join('\n\n') : '- Sin commits asociados en este segmento.',
    commentSection
  ].filter(Boolean);
  return sections.join('\n\n');
}

const aiSystemPrompt = 'Converti JSON tecnico compacto a markdown legible para README. No inventes nada. Conserva todos los datos. IMPORTANTE: Incluye un breve resumen de los comentarios de Jira. Claves: r=release, k=sis, pt/pc=parte, s=detalle SIS, st=estado, tp=tipo, p=prioridad, a=responsable, l=labels, cp=componentes, fv=fixVersions, rs=sis relacionados, rr=rec, d=descripcion, cm=comentarios, c=commits, sh=sha, dt=fecha, au=autor, m=mensaje, sg=stats, f=archivos, p/s/a/d/c=ruta estado adds dels changes.';

const baseSummary = (fullEvidence.diagnostics && fullEvidence.diagnostics.stats) || (rawRelease.diagnostics && rawRelease.diagnostics.stats) || {};

// Drop merge commits aggressively here in case old payloads are sent
const commitsWithoutSis = (fullEvidence.commitsWithoutSis || (rawRelease.diagnostics ? rawRelease.diagnostics.commitsWithoutSIS : []) || [])
  .filter(c => !c.isMergeCommit && !/^merge\b/i.test(String(c.message || '').trim()));

const sisWithoutRec = fullEvidence.sisWithoutRec || (rawRelease.diagnostics ? rawRelease.diagnostics.sisWithoutREC : []) || [];
const requestedBatchIndex = input.batchIndex ? Number(input.batchIndex) : null;
const localAiBaseUrl = String(input.localAiBaseUrl || 'http://localhost:11434').trim() || 'http://localhost:11434';
const localAiModel = String(input.localAiModel || 'qwen3:32b').trim() || 'qwen3:32b';
const maxAiPayloadChars = Math.max(4000, Math.min(Number(input.maxAiPayloadChars || 12000), 24000));
const maxCommitsPerSegment = Math.max(1, Math.min(Number(input.batchCommitSize || 5), 50));

if (requestedBatchIndex !== null && (!Number.isInteger(requestedBatchIndex) || requestedBatchIndex < 1)) {
  throw new Error('batchIndex debe ser un entero positivo o vacio para procesar todos los lotes.');
}

if (input.legacyPrompt) {
  return [{ json: { kind: 'technicalBatchRequest', batchIndex: 1, batchCount: 1, totalBatchCount: 1, batchCommitShas: [], batchSisKeys: [], release: input.release || {}, prompt: input.legacyPrompt, aiInputJson: input.legacyPrompt, aiSystemPrompt: aiSystemPrompt, technicalMarkdown: input.legacyPrompt, globalSummary: globalSummary, commitsWithoutSis: commitsWithoutSis, sisWithoutRec: sisWithoutRec, localAiBaseUrl: localAiBaseUrl, localAiModel: localAiModel } }];
}

// Drop merge commits aggressively here too
const commits = asArray(rawRelease.commits)
  .map(sanitizeCommit)
  .filter(c => !c.isMergeCommit);

const workItems = asArray(rawRelease.workItems).map(sanitizeIssue);
const recItems = asArray(rawRelease.recItems).map(sanitizeIssue);
const relationships = rawRelease.relationships || {};
const globalSummary = {
  ...baseSummary,
  commits: commits.length || baseSummary.commits,
  commitsWithFiles: commits.filter((commit) => commit.files.length > 0).length,
  filesTotal: commits.reduce((total, commit) => total + commit.files.length, 0)
};
const commitToSis = asArray(relationships.commitToSis);
const releaseVersion = (input.release && input.release.currentVersion) || (rawRelease.release && rawRelease.release.currentVersion) || 'sin-version';
const recMap = new Map(recItems.map((item) => [item.key, item]));
const commitsBySha = new Map(commits.filter((commit) => commit.sha).map((commit) => [commit.sha, commit]));
const sisToCommitShas = new Map();

for (const relation of commitToSis) {
  if (!relation || !relation.sisKey || !relation.commitSha) continue;
  if (!sisToCommitShas.has(relation.sisKey)) sisToCommitShas.set(relation.sisKey, []);
  sisToCommitShas.get(relation.sisKey).push(relation.commitSha);
}

if (!commits.length && !workItems.length) {
  const technicalMarkdown = '### Sin evidencia\n\n- No se encontraron commits ni SIS en la evidencia.';
  return [{ json: { kind: 'technicalBatchRequest', batchIndex: 1, batchCount: 1, totalBatchCount: 1, batchCommitShas: [], batchSisKeys: [], release: input.release || {}, globalSummary: globalSummary, commitsWithoutSis: commitsWithoutSis, sisWithoutRec: sisWithoutRec, localAiBaseUrl: localAiBaseUrl, localAiModel: localAiModel, aiSystemPrompt: aiSystemPrompt, aiInputJson: JSON.stringify({ r: releaseVersion, note: 'sin evidencia' }), prompt: 'compact-ai-input', technicalMarkdown: technicalMarkdown } }];
}

const sisSegments = [];
for (const issue of workItems) {
  if (!issue.key) continue;
  const relatedCommitShas = unique(issue.originCommitShas.concat(asArray(sisToCommitShas.get(issue.key)), commits.filter((commit) => commit.originSisKeys.includes(issue.key)).map((commit) => commit.sha)));
  const linkedCommits = relatedCommitShas.map((sha) => commitsBySha.get(sha)).filter(Boolean);
  const issuePayload = buildCompactIssue(issue, linkedCommits, recMap);
  const segments = splitIssueByBudget(issuePayload, maxAiPayloadChars, releaseVersion, maxCommitsPerSegment);
  for (const payload of segments) {
    sisSegments.push({
      sisKey: issue.key,
      payload,
      technicalMarkdown: renderSegmentMarkdown(payload, recMap),
      batchCommitShas: unique(asArray(payload.s.c).map((commit) => commit.sh).filter(Boolean))
    });
  }
}

if (!sisSegments.length) {
  const technicalMarkdown = '### Sin SIS procesables\n\n- No se generaron segmentos por SIS con la evidencia disponible.';
  return [{ json: { kind: 'technicalBatchRequest', batchIndex: 1, batchCount: 1, totalBatchCount: 1, batchCommitShas: [], batchSisKeys: [], release: input.release || {}, globalSummary: globalSummary, commitsWithoutSis: commitsWithoutSis, sisWithoutRec: sisWithoutRec, localAiBaseUrl: localAiBaseUrl, localAiModel: localAiModel, aiSystemPrompt: aiSystemPrompt, aiInputJson: JSON.stringify({ r: releaseVersion, note: 'sin sis procesables' }), prompt: 'compact-ai-input', technicalMarkdown: technicalMarkdown } }];
}

const groupedBatches = [];
let currentBatch = [];
let currentSisCount = 0;
let currentLength = 0;

for (const seg of sisSegments) {
  const segLength = JSON.stringify(seg.payload).length;

  if (currentBatch.length > 0 && (currentSisCount >= maxCommitsPerSegment || currentLength + segLength > maxAiPayloadChars)) {
    groupedBatches.push(currentBatch);
    currentBatch = [];
    currentSisCount = 0;
    currentLength = 0;
  }

  currentBatch.push(seg);
  currentSisCount += 1;
  currentLength += segLength;
}
if (currentBatch.length > 0) {
  groupedBatches.push(currentBatch);
}

const selectedBatches = requestedBatchIndex === null ? groupedBatches : [groupedBatches[requestedBatchIndex - 1]].filter(Boolean);
if (!selectedBatches.length) {
  throw new Error('batchIndex fuera de rango. Lotes disponibles: ' + groupedBatches.length + '.');
}

return selectedBatches.map((batch, selectedIndex) => {
  const sourceBatchIndex = requestedBatchIndex === null ? selectedIndex + 1 : requestedBatchIndex;
  const combinedPayload = batch.map(b => b.payload);
  const combinedMarkdown = batch.map(b => b.technicalMarkdown).join('\n\n');
  const combinedSisKeys = unique(batch.map(b => b.sisKey));
  const combinedCommitShas = unique(batch.flatMap(b => b.batchCommitShas));

  return {
    json: {
      kind: 'technicalBatchRequest',
      batchIndex: sourceBatchIndex,
      batchCount: selectedBatches.length,
      totalBatchCount: groupedBatches.length,
      batchCommitShas: combinedCommitShas,
      batchSisKeys: combinedSisKeys,
      sisKey: combinedSisKeys.join(', '),
      release: input.release || rawRelease.release || {},
      globalSummary: globalSummary,
      commitsWithoutSis: commitsWithoutSis,
      sisWithoutRec: sisWithoutRec,
      localAiBaseUrl: localAiBaseUrl,
      localAiModel: localAiModel,
      maxAiPayloadChars: maxAiPayloadChars,
      aiSystemPrompt: aiSystemPrompt.replace('Converti JSON tecnico compacto', 'Converti el arreglo de JSONs tecnicos compactos'),
      aiInputJson: JSON.stringify(combinedPayload),
      prompt: 'compact-ai-json',
      technicalMarkdown: combinedMarkdown
    }
  };
});

function cleanCommitMessage(message) {
  let text = String(message || '');
  text = text.replace(/\/\*+/g, ' ');
  text = text.replace(/\*+\//g, ' ');
  text = text.replace(/(^|\s)\/+(?=\S)/g, ' ');
  text = text.replace(/(?<=\S)\/+(?=\s|$)/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function normalizeMarkdown(text) {
  return String(text || '')
    .replace(/Mensaje:\s*(.+)$/gm, (_, message) => 'Mensaje: ' + cleanCommitMessage(message))
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function countSectionItems(markdown, heading) {
  const text = String(markdown || '');
  const escaped = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp('^' + escaped + '\\s*$([\\s\\S]*?)(?=^####?#?\\s|\\Z)', 'im');
  const match = text.match(regex);
  if (!match) return 0;
  return match[1]
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => /^-\s+/.test(line)).length;
}

function shouldUseFallback(fallback, candidate) {
  if (!candidate) return true;

  const fallbackHasComments = fallback.includes('#### Resumen de comentarios Jira');
  const candidateHasComments = candidate.includes('#### Resumen de comentarios Jira');
  if (fallbackHasComments && !candidateHasComments) return true;

  const fallbackHasFiles = fallback.includes('##### Archivos modificados');
  const candidateHasFiles = candidate.includes('##### Archivos modificados');
  if (fallbackHasFiles && !candidateHasFiles) return true;

  const fallbackCommentItems = countSectionItems(fallback, '#### Resumen de comentarios Jira');
  const candidateCommentItems = countSectionItems(candidate, '#### Resumen de comentarios Jira');
  if (candidateCommentItems < fallbackCommentItems) return true;

  const fallbackFileItems = countSectionItems(fallback, '##### Archivos modificados');
  const candidateFileItems = countSectionItems(candidate, '##### Archivos modificados');
  if (candidateFileItems < fallbackFileItems) return true;

  return false;
}

const source = (() => {
  try {
    return $('Build technical commit batches').item.json || {};
  } catch (error) {
    return {};
  }
})();

const current = $json || {};
const fallbackMarkdown = normalizeMarkdown(current.technicalMarkdown || source.technicalMarkdown || '');
const aiSource = current.output || current.text || current.response || current.body?.output || current.body?.text || current.body?.response || '';
const aiMarkdown = normalizeMarkdown(aiSource);
const errorText = String(current.error?.message || current.error?.description || current.message || current.body?.error || '').trim();
const fallbackRequired = shouldUseFallback(fallbackMarkdown, aiMarkdown);
const markdown = fallbackRequired ? fallbackMarkdown : aiMarkdown;
let status = 'generated';

if (fallbackRequired) {
  if (/timeout|timed out|aborted|socket hang up|ECONNRESET|offline/i.test(errorText)) {
    status = 'timeoutFallback';
  } else if (errorText) {
    status = 'requestErrorFallback';
  } else if (aiMarkdown && aiMarkdown !== fallbackMarkdown) {
    status = 'generatedWithFallback';
  } else {
    status = 'emptyResponseFallback';
  }
}

return {
  json: {
    kind: 'technicalBatchMarkdown',
    batchIndex: Number(current.batchIndex || source.batchIndex || 0),
    batchCount: Number(current.batchCount || source.batchCount || 0),
    batchCommitShas: Array.isArray(current.batchCommitShas) ? current.batchCommitShas : (Array.isArray(source.batchCommitShas) ? source.batchCommitShas : []),
    batchSisKeys: Array.isArray(current.batchSisKeys) ? current.batchSisKeys : (Array.isArray(source.batchSisKeys) ? source.batchSisKeys : []),
    sisKey: current.sisKey || source.sisKey || null,
    release: current.release || source.release || {},
    globalSummary: current.globalSummary || source.globalSummary || {},
    commitsWithoutSis: Array.isArray(current.commitsWithoutSis) ? current.commitsWithoutSis : (Array.isArray(source.commitsWithoutSis) ? source.commitsWithoutSis : []),
    sisWithoutRec: Array.isArray(current.sisWithoutRec) ? current.sisWithoutRec : (Array.isArray(source.sisWithoutRec) ? source.sisWithoutRec : []),
    technicalMarkdown: markdown || null,
    status: status,
    error: errorText || null
  }
};

const rows = $input.all().map((item) => item.json || {});
const ordered = rows.sort((a, b) => Number(a.batchIndex || 0) - Number(b.batchIndex || 0));
if (!ordered.length) throw new Error('No technical batch markdown was generated.');

function cleanCommitMessage(message) {
  let text = String(message || '');
  text = text.replace(/\/\*+/g, ' ');
  text = text.replace(/\*+\//g, ' ');
  text = text.replace(/(^|\s)\/+(?=\S)/g, ' ');
  text = text.replace(/(?<=\S)\/+(?=\s|$)/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function cleanText(text) {
  let value = String(text || '').trim();
  value = value.replace(/^#\s+Release\s+.*?\n+/i, '');
  value = value.replace(/^##\s+Alcance tecnico\n+[\s\S]*?(?=^##\s|^###\s|\Z)/im, '');
  value = value.replace(/^##\s+Resumen de trazabilidad\n+[\s\S]*?(?=^##\s|^###\s|\Z)/im, '');
  value = value.replace(/Mensaje:\s*(.+)$/gm, (_, message) => 'Mensaje: ' + cleanCommitMessage(message));
  value = value.split(/\r?\n/).filter((line) => !/^\s*-{3,}\s*$/.test(line)).join('\n');
  value = value.replace(/\n{3,}/g, '\n\n');
  return value.trim();
}

const release = ordered[0].release || {};
const releaseVersion = release.currentVersion || 'sin-version';
const globalSummary = ordered[0].globalSummary || {};
const commitsWithoutSis = ordered[0].commitsWithoutSis || [];
const sisWithoutRec = ordered[0].sisWithoutRec || [];
const mergedBatches = ordered.map((row) => cleanText(row.technicalMarkdown)).filter(Boolean).join('\n\n').trim();

const summaryLines = [
  ['Commits totales', globalSummary.commits],
  ['Commits con archivos', globalSummary.commitsWithFiles],
  ['Archivos totales', globalSummary.filesTotal],
  ['SIS primarios', globalSummary.primarySis],
  ['SIS relacionados', globalSummary.relatedSis],
  ['REC', globalSummary.recs],
  ['SIS con comentarios', globalSummary.sisWithComments]
].filter((entry) => entry[1] !== undefined && entry[1] !== null).map((entry) => '- ' + entry[0] + ': ' + entry[1]).join('\n');

const commitsWithoutSisLines = commitsWithoutSis.length ? commitsWithoutSis.filter((commit) => !Boolean(commit && commit.isMergeCommit) && !/^merge\b/i.test(String(commit && commit.message || ''))).slice(0, 120).map((commit) => {
  const shortSha = commit && commit.sha ? String(commit.sha).slice(0, 10) : 'sin-sha';
  const message = cleanCommitMessage((commit && commit.message) || 'sin mensaje');
  return '- ' + shortSha + ': ' + message;
}).join('\n') : '';

const sisWithoutRecLines = sisWithoutRec.length ? sisWithoutRec.map((key) => '- ' + key).join('\n') : '';

let finalReadme = '# Release ' + releaseVersion + '\n';
if (summaryLines) finalReadme += '\n## Resumen de trazabilidad\n' + summaryLines + '\n';
if (mergedBatches) finalReadme += '\n## Cambios detallados\n' + mergedBatches + '\n';
if (commitsWithoutSisLines) finalReadme += '\n## Commits sin SIS\n' + commitsWithoutSisLines + '\n';
if (sisWithoutRecLines) finalReadme += '\n## SIS sin REC\n' + sisWithoutRecLines + '\n';
finalReadme = finalReadme.replace(/\n{3,}/g, '\n\n').trim();

return [{ json: { kind: 'technicalReadmeResult', status: finalReadme ? 'generated' : 'emptyResponse', technicalReadme: finalReadme || null, output: finalReadme || null, text: finalReadme || null, response: finalReadme || null, mergedMarkdown: mergedBatches || null, batchSummaries: ordered.map((row) => ({ batchIndex: row.batchIndex, sisKey: row.sisKey || null, batchCommitShas: row.batchCommitShas || [], batchSisKeys: row.batchSisKeys || [], status: row.status || 'unknown', error: row.error || null })) } }];
